IsotropicLTC GGX_reflection_LTC_coefficients(float cos_theta_o, float roughness) {
    float u = sqrtf(fmaxf(0.0f, 1 - cos_theta_o));
    Vector4f ltc_params = ImageSampling::bilinear(GGX_reflection_LTC_params, GGX_reflection_roughness_sample_count, GGX_reflection_angle_sample_count, u, roughness);
    return { ltc_params.x, 1, ltc_params.w, ltc_params.y, ltc_params.z };
}

